                background: "oklch(0.12 0.02 50)",
                borderBottom: "1px solid var(--gold-dim)",
              }}
            >
              <div className="flex gap-1.5">
                {[
                  "oklch(0.50 0.08 77)",
                  "oklch(0.55 0.08 77)",
