              </div>
              {mockLog.map((entry) => (
                <div
                  key={entry.date}
                  className="flex items-center gap-4 pb-3"
                  style={{ borderBottom: "1px solid oklch(1 0 0 / 0.05)" }}
                >
                  <span
                    className="text-xs shrink-0 w-24"
                    style={{ color: "oklch(0.40 0.06 65)" }}
                  >
                    {entry.date}
