                    {tag}
                  </span>
                ))}
              </div>
            </div>

            {/* 統計 */}
            <div
              className="juku-glass p-5 flex flex-col gap-4"
              style={{ border: "1px solid oklch(1 0 0 / 0.08)" }}
            >
              <span
                className="font-noto-serif-jp font-bold text-sm"
                style={{ color: "var(--foreground)" }}
              >
                今月の統計
