              <div className="grid grid-cols-2 gap-4">
                {[
                  { label: "学習日数", value: "18日" },
                  { label: "総時間",   value: "24h" },
                  { label: "解いた問題", value: "312問" },
                  { label: "正答率",   value: "78%" },
                ].map((stat) => (
                  <div key={stat.label} className="flex flex-col gap-1">
                    <span
                      className="font-space-mono text-xs"
                      style={{ color: "var(--muted-foreground)" }}
